SourceCode.Declaration:
/// <summary>
/// Extension of PurchLine data source on PurchTable form.
/// Controls the enablement of Dockage Split Item checkbox
/// based on ETG Canada parameters.
/// </summary>
[ExtensionOf(formDataSourceStr(PurchTable, PurchLine))]
final class ETGPurchLine_DS_Extension
{
}

Method.Source:
public int active()
{
    int ret = next active();
    this.applyDockageControl();

    return ret;
}

private void applyDockageControl()
{
    ETGCanadaParameters params = ETGCanadaParameters::find();

    FormRun formRun = this.formRun();
    FormCheckBoxControl dockageCtrl =formRun.design().controlName(formControlStr(PurchTable, PurchLine_ETGIsDockageItem));
    FormCheckBoxControl splitCtrl =formRun.design().controlName(formControlStr(PurchTable, PurchLine_ETGIsSplitItem));

    boolean enableFields = (params && params.EnableDockageSplitItems == NoYes::Yes);


    if (dockageCtrl )
    {

        dockageCtrl.visible(enableFields);
        dockageCtrl.allowedit(false);

    }
    if (splitCtrl)
    {
        splitCtrl.visible(enableFields);
        splitCtrl.allowedit(false);
    }
}
